function levelFromXp(xp: number): number {
  let level = 0
  while (xpForLevel(level + 1) <= xp) level++
  return level
}
// Level 0 is the starting level (no XP spent)

// CombatScreen level-up useEffect
const unlocked = SKILLS.find(s => s.classId === classId && s.levelRequired === level) ?? null
const nextUpcoming = SKILLS
  .filter(s => s.classId === classId && s.levelRequired > level)
  .sort((a, b) => a.levelRequired - b.levelRequired)[0] ?? null
setLevelUpSkill(unlocked)
setLevelUpNextSkill(nextUpcoming)

